INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'clubs', '16 pixels - photography vinteo - filmmaking palette - art cinematic - film Samvaad - debating abhinaya - drama sargam - music stepup - dance Orenda - Inclusivity and Expression Club. tech clubs - metis - coding mean mechanics - robotics Digis - digital sports odyssey - astronomy Scale - machine learning club Grasp - competitive programming Moksha - motorsport club', 'Cultural clubs at IIT Gandhinagar: 16 Pixels (Photography), Vinteo (Filmmaking), Palette (Art), Cinematic (Film), Samvaad (Debating), Abhinaya (Drama), Sargam (Music), StepUp (Dance), Orenda (Inclusivity and Expression). Technical clubs: Metis (Coding), Mean Mechanics (Robotics), Digis (Digital Sports), Odyssey (Astronomy), Scale (Machine Learning), Grasp (Competitive Programming), Moksha (Motorsport).', 1, '01/04/26 2:01 am', '01/04/26 2:01 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'attendance', '80% attendance in Foundation Programme and Physical Education in 1st year and 50% attendance in 2nd year P.E are mandatory. For all other courses attendance policies changes from course to course and completely depends on professor. There can be 0 attendance policy or 50 or 80, whatever the professor wish. If majority of students feel that the attendance policy is unfair like 100 percent they can negotiate with that specific prof.', 'At IIT Gandhinagar, 80% attendance is mandatory in Foundation Programme and Physical Education in 1st year, and 50% in 2nd year PE. For all other courses, attendance policy varies by course and depends entirely on the professor - it can range from 0% to 80%. If a majority of students find the policy unfair, they can negotiate with the professor.', 1, '31/03/26 11:10 pm', '31/03/26 11:10 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'wifi', '24/7 wifi throughout the campus. every hostel room has a lan wire to connect, ACs work during summer nights. all the classrooms have central AC. A pantry with 1 refrigerator, 1 electric stove, 1 oven and a water dispenser is available in every floor in hostels', 'IIT Gandhinagar has 24/7 WiFi throughout campus. Every hostel room has a LAN wire. ACs work during summer nights in hostels. All classrooms have central AC. A pantry with refrigerator, electric stove, oven, and water dispenser is available on every floor in hostels.', 1, '01/04/26 2:26 am', '01/04/26 2:26 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'fests', 'Amaltea - tech fest around 3 days - happens in odd semester during october/november. Blithchron - cultural fest 3 days - during even sem february - most popular fest. TEDx - feb/march - one day event with several speakers. small events like open mic where people sing/tell poetry etc at center of the hostel area panchayat. events conducted by clubs like stepup, abhinaya, palette etc. Sports events - Hallabol Jan/Feb regular sports with new fun and challenging rules everyone in the iitgn community can participate even working staff, faculty etc. General championship march/april students compete batch wise like btech 1st 2nd 3rd 4th years masters phds. students represent their batch in several sports. finally whichever batch has highest cumulative points wins the championship', 'IIT Gandhinagar hosts two major fests: Amalthea (tech fest, ~3 days, Oct/Nov in odd semester) and Blithchron (cultural fest, 3 days, February in even semester - most popular fest). Other events include TEDx (Feb/March, one day), open mic events at Panchayat (hostel area center), and club-organized events. Sports events: Hallabol (Jan/Feb - sports with fun rules, open to students, staff, and faculty) and General Championship (March/April - batch-wise competition where the batch with highest cumulative points wins).', 2, '01/04/26 2:06 am', '01/04/26 2:06 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'hostels', 'Hostel - Aibaan Beauki Chimair Girls. Boys hostels - Duven Emite Firpeal Griwiksh Hiqom Ijoka Jurqia Kyzeel Lekhaag. For girls there are 2 types of room double and single. 1st 2nd and 3rd years gets double rooms. 4th year Mtech and some of the PHD students gets single rooms. Boys - triple double single. generally till last year 1st 2nd years got triple and 3rd 4th got single. But from this year mostly in future as well 1st years both Btech and Mtech double. 2nd 3rd triple. 4th Mtech 2nd and some PHD single. All this single/double/triple for specific batch is decided by the administration. for specific room students can choose by filling a hostel allocation form that is floated at the start of each academic year. this is allocated based on first come first serve basis. for Phd students who are married/with family will get housing blocks within the campus', 'IIT Gandhinagar has 12 hostels. Girls: Aibaan, Beauki, Chimair (1st/2nd/3rd year double rooms, 4th year/MTech/PhD single rooms). Boys: Duven, Emite, Firpeal, Griwiksh, Hiqom, Ijoka, Jurqia, Kyzeel, Lekhaag. Current boys policy: 1st year (BTech + MTech) double, 2nd/3rd year triple, 4th year/MTech 2nd year/some PhD single. Room allocation via hostel form at start of academic year on first-come-first-serve basis. Married PhD students get housing blocks on campus.', 1, '31/03/26 11:21 pm', '31/03/26 11:21 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'mess', 'right now there are 4 messes for the entire iitgn community. Rgouras Mohani Jaiswal and Bhopal. similar to hostel allocation mess is also allocated through a google form based of first come first serve. This form is floated every half semester so students can choose their favorite mess every half sem. for 1st year each mess is allocated for 2 weeks after that they can choose the mess they like through google form ofcourse if they were able to fill the form quickly', 'IIT Gandhinagar has 4 messes: R Gouras, Mohani, Jaiswal, and Bhopal. Mess allocation is done via Google form on first-come-first-serve basis. The form is floated every half semester, so students can change mess every half semester. First-year students are allocated each mess for 2 weeks initially, then they can choose via the Google form.', 1, '31/03/26 11:35 pm', '31/03/26 11:35 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'laundry', 'common laundry is the one that took a contract at our campus. they take laundry bags twice a week. on what specific day is depended on the hostel you are in. other than that there are 3 smart laundry machines in student lounge which can used through online bookings - students can wash their clothes using those machines. other facility is Safety laundry an outlet kinda thing. you give your clothes they say the price and no.of days you come back after certain days pay the money and take your clothes.', 'IIT Gandhinagar has three laundry options: (1) Common Laundry - contracted service that collects laundry bags twice a week, schedule depends on hostel. (2) 3 Smart Laundry machines in Student Lounge with online booking system. (3) Safety Laundry - a drop-off service where you pay per item and pick up after specified days.', 1, '31/03/26 11:41 pm', '31/03/26 11:41 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'elections', 'elections conducted in march every year. posts - Secretaries General Welfare Sports Academic Cultural FOR WHOLE IITGN COMMUNITY. Senetors 4 from every batch Btech 1st 2nd 3rd 4th whole Mtech. 1 girl senetor for whole community. CRs every batch every branch. election commision is reponsible for conducting elections with guidelines and rules. secretary candidates can have campainers from each batch', 'Elections at IIT Gandhinagar are held in March every year. Posts include: Secretaries (General, Welfare, Sports, Academic, Cultural) for the whole IITGN community; Senators (4 from each batch - BTech 1st through 4th year, whole MTech, plus 1 girl senator for the community); and CRs for every batch and branch. Election commission conducts elections. Secretary candidates can have campaigners from each batch.', 1, '31/03/26 11:48 pm', '31/03/26 11:48 pm', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'sports', 'Have a dedicated sports complex. Almost all sports are available. Cricket Football Volleyball Athletics Aquatics Tennis Table tennis Squash Badminton Basketball weightlifting etc. 1 Football ground. 2 cricket pitches 1 professional 1 for people playing for fun. 3 basketball courts 2 outdoor 1 indoor. 4 outdoor tennis courts. 2 badminton halls each with 3 courts. 4 separate badminton courts in hostel area. 3 volleyball courts 2 outdoor 1 indoor. 400m athletics track. 1 Gym large enough includes weightlifting facility. 2 swimming pools 50x25m 25x10m. Table tennis dedicated hall. Squash dedicated hall. Yoga room. even have a hockey field but no team/trainer. almost all of these sports have trainers', 'IIT Gandhinagar has a dedicated sports complex. Facilities include: 1 football ground, 2 cricket pitches (1 professional, 1 casual), 3 basketball courts (2 outdoor, 1 indoor), 4 outdoor tennis courts, 2 badminton halls with 3 courts each + 4 separate courts in hostel area, 3 volleyball courts (2 outdoor, 1 indoor), 400m athletics track, 1 large gym with weightlifting, 2 swimming pools (50x25m and 25x10m), dedicated Table Tennis hall, Squash hall, Yoga room, and a hockey field (no team/trainer). Almost all sports have trainers.', 1, '01/04/26 1:01 am', '01/04/26 1:01 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'canteen', 'hostel area - 1 bakery 1 amul store 1 fruit juice stall 1 tea post 1 south indian tiffins 1 fast food stall 2 pure veg stalls instant coffee shakes sandwiches vadapav pizza toasts etc 1 nescafe 2 general stores 1 saloon seperate for men and women. Academic area - 1 nescafe 2 cafeterias. Sports complex - 1 fruit juice stall. cental arcade - 1 sandwich stall 1 supermart 1 bookstall 1 laundry shop 1 apollo pharmacy 1 fruits/veggies stall 1 snack stall like samosa chole etc 1 post office 1 iitgn logo items stall. other than these there will be some temporary stalls for trails regularly at hostel area', 'IIT Gandhinagar campus outlets - Hostel area: bakery, Amul store, fruit juice stall, Tea Post, South Indian tiffins, fast food stall, 2 pure veg stalls (coffee, shakes, sandwiches, vadapav, pizza, toasts), Nescafe, 2 general stores, salon. Academic area: Nescafe, 2 cafeterias. Sports complex: fruit juice stall. Central Arcade: sandwich stall, supermart, bookstall, laundry shop, Apollo Pharmacy, fruits/veggies stall, snack stall, post office, IITGN logo items stall. Temporary trial stalls appear regularly.', 1, '01/04/26 1:09 am', '01/04/26 1:09 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'fines', 'there is no fines policy unless you break some campus property. but there is disciplinary committee called SSAC that almost involves in everything. if someone causes any issue that causes problems to others spoiling campus properties any kind of cheating etc will lead you to that committee and based on your case you will be given social hours you have to work the given no of hours doing charity work on campus / semester back / year back / removing from hostel you have to stay out of the campus etc', 'IIT Gandhinagar has no fines policy unless you break campus property. The disciplinary committee SSAC handles issues. Punishments based on severity include: social hours (charity work on campus), semester back, year back, or removal from hostel (must stay off campus). Offenses include property damage, cheating, and causing problems to others.', 1, '01/04/26 1:25 am', '01/04/26 1:25 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'gym', 'Have a dedicated sports complex. 1 Gym large enough includes weightlifting facility. 2 swimming pools 50x25m 25x10m', 'IIT Gandhinagar has 1 large gym with weightlifting facility inside the sports complex. There are also 2 swimming pools (50x25m and 25x10m).', 1, '01/04/26 1:01 am', '01/04/26 1:01 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'medical', 'apollo pharmacy is available. ambulance services are available. medical center is available at central arcade 24/7. everyday there will be a gynecologist a physician a physiotherapist etc. every single day we get a mail from medical services on who is available and from what time to what time. if the problem requires serious medical attention they will refer to out of the campus hospitals and all the expenditure out there will be reimbursed later provided you submit all the bills. other than this there are also mental health services with whom you can always talk about anything whenever you feel stressed want to share something etc', 'IIT Gandhinagar has Apollo Pharmacy on campus, ambulance services, and a 24/7 medical center at Central Arcade. Daily availability of gynecologist, physician, physiotherapist, etc. Daily email sent to all students with doctor availability and timings. Serious cases are referred to outside hospitals with full expense reimbursement on submitting bills. Mental health services are also available for students anytime.', 1, '01/04/26 1:33 am', '01/04/26 1:33 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'transport', 'free buses are available from campus to kudasan everyday at specific times. free buses to railwaystation and airport will be available at the time of vacations. Sardar vallababai international airport is around 16kms. sabarmati railway station gandhinagar 18kms. ahmedabad junction 22kms', 'IIT Gandhinagar provides free daily buses from campus to Kudasan. Free buses to railway station and airport during vacations. Sardar Vallabhbhai Patel International Airport is ~16 km away. Sabarmati Railway Station (Gandhinagar) is ~18 km. Ahmedabad Junction is ~22 km.', 1, '01/04/26 1:19 am', '01/04/26 1:19 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'restaurants', 'there are 2 fastfood like restaurants that only delivers to our campus we can just order on whatsapp. Zomato is available. Bigbasket is available. if you want to go outside there are areas like kudasan within 5-6kms from our campus where you can find almost any kind of restaurant.', 'IIT Gandhinagar has 2 fast-food restaurants that deliver exclusively to campus via WhatsApp orders. Zomato and Bigbasket are available. Kudasan area (5-6 km from campus) has almost any kind of restaurant.', 1, '01/04/26 1:12 am', '01/04/26 1:12 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'tourist', 'around here we have akshardham gandhi ashram sabarmati ashram several riverfonts around sabarmati river in gandhinagar and ahmedabad. other tourist places like stepwell in ahmedabad. also 1 day tours like ekta nagar vadodara etc', 'Tourist spots near IIT Gandhinagar: Akshardham, Gandhi Ashram, Sabarmati Ashram, Sabarmati Riverfronts (Gandhinagar and Ahmedabad), Stepwell in Ahmedabad. Day trips: Ekta Nagar, Vadodara.', 1, '01/04/26 1:39 am', '01/04/26 1:39 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'malls', 'several malls in gadhinagar like swagat mall agora mall etc. and ahmedabad is one of the metro cities so we can find many malls like pheonix mall palladium mall nexus one Imax etc', 'Malls near IIT Gandhinagar: In Gandhinagar - Swagat Mall, Agora Mall. In Ahmedabad (metro city) - Phoenix Mall, Palladium Mall, Nexus One, IMAX.', 1, '01/04/26 1:41 am', '01/04/26 1:41 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'climate', 'temperature go from almost single digit like 8/9 to 24/25 degrees in winters and 25 to 38/40 in summers. very humid. though sometimes temperatures are low it feels too hot. likewise it will be too cold in winters aswell.', 'IIT Gandhinagar climate: Winters 8-25 degrees Celsius, Summers 25-40 degrees Celsius. Very humid - sometimes low temperatures still feel hot. Winters can feel very cold as well.', 1, '01/04/26 1:45 am', '01/04/26 1:45 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'language', 'oncampus english works well although most prefer hindi. outside the campus people speak hindi well. professors use english mostly. other cleaning staff workers outlet staff all speaks hindi.', 'At IIT Gandhinagar, English works well on campus though most prefer Hindi. Outside campus, Hindi is widely spoken. Professors mostly use English. Staff (cleaning, workers, outlets) speak Hindi.', 1, '01/04/26 1:47 am', '01/04/26 1:47 am', 'whatsapp');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'document_ocr', 'fee_structure', 'Fee structure B.Tech/B.S. Academic Year 2025-26 Semester I. General: Tuition 100000, Semester Facilities 2000, Student Welfare 1000, Medical Insurance 3000, One Time Admission 12150, Hostel Room Rent 6000, Mess and Laundry 28600, Total First Semester 152750. SC/ST/PwD: Total 41750. Income below 1L: Total 41750. Income 1L-5L: Total 85950.', 'IIT Gandhinagar B.Tech/B.S. fee structure (2025-26, Semester I): General category total Rs 1,52,750 (Tuition Rs 1,00,000 + Facilities Rs 2,000 + Welfare Rs 1,000 + Medical Insurance Rs 3,000 + One-time Admission Rs 12,150 + Hostel Rent Rs 6,000 + Mess/Laundry Rs 28,600). SC/ST/PwD: Rs 41,750. Income below Rs 1 lakh: Rs 41,750. Income Rs 1-5 lakh: Rs 85,950. Tuition exempted for SC/ST/PwD, full remission below Rs 1 lakh, 2/3 remission for Rs 1-5 lakh.', 1, '31/03/26', '31/03/26', 'pdf_ocr');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'document_ocr', 'academics', 'UG Curriculum Institute Level Plan. 1st sem: Foundation Programme, Intro to Writing, World Civilizations, Calculus, Engineering Graphics, Computing, Design Innovation and Prototyping, Materials for Future, PE. 2nd sem: General Education, Writing II, Differential Equations, Undergrad Science Lab, Data Centric Computing, Probability and Statistics, Electrical Engineering, World of Engineering, PE. Branch specific courses start from 3rd semester. Students can choose Sci/Math baskets and electives from a given list. 28 credits in 1st sem, 22 in 2nd sem, reducing to 8-10 in later semesters.', 'IIT Gandhinagar UG Curriculum has an Institute Level Plan. 1st semester (28 credits): Foundation Programme, Intro to Writing, World Civilizations, Calculus, Engineering Graphics, Computing, Design Innovation and Prototyping, Materials for Future, PE. 2nd semester (22 credits): General Education, Writing II, Differential Equations, Undergrad Science Lab, Data Centric Computing, Probability and Statistics, Electrical Engineering, World of Engineering, PE. Branch-specific courses start from 3rd semester. Students choose Sci/Math baskets and electives. Credits reduce to 8-10 in later semesters as electives increase.', 1, '31/03/26', '31/03/26', 'image_ocr');
INSERT INTO training_data (college, chunk_type, topic, raw_text, cleaned_text, message_count, timestamp_start, timestamp_end, source) VALUES ('IIT Gandhinagar', 'ambassador_message', 'other_data', 'Hostels inter hostel mobility boys and girls are allowed to go to they opp gender hostels ofcourse with their and their roommate consent. you can go out of campus whenever you want. class room booking you can book classrooms using google calender during exam times to study. Library have a large library 9 am to 12 am and a mini library 24/7 have a website to check books availability and their location in library.', 'At IIT Gandhinagar, inter-hostel mobility allows boys and girls to visit opposite gender hostels with consent. Students can leave campus anytime - no curfew. Classrooms can be booked via Google Calendar during exam times for studying. The campus has a large library (9 AM to 12 AM) and a mini library (24/7), with a website to check book availability and location.', 1, '01/04/26 1:55 am', '01/04/26 1:55 am', 'whatsapp');
